const cp = require('child_process');
const scanDir = '__DOCUMENTS_DIR__';
const projRoot = '__PROJECT_ROOT__';

try {
  const raw = cp.execSync('bash scripts/scan-projects.sh "' + scanDir + '" 2>&1', {cwd: projRoot, timeout: 60000, encoding: 'utf8'});
  const now = Math.floor(Date.now() / 1000);
  const projects = raw.trim().split(String.fromCharCode(10)).filter(l => l.includes('|')).map(l => {
    const [name, branch, last, age, uncommitted, manifest, tpl] = l.split('|');
    const days = parseInt(age) ? Math.floor((now - parseInt(age)) / 86400) : 999;
    const activity = days <= 1 ? 'hot' : days <= 7 ? 'warm' : days <= 30 ? 'cool' : 'cold';
    const color = {hot:'#22c55e',warm:'#eab308',cool:'#94a3b8',cold:'#ef4444'}[activity];
    return {name, branch, last, days, uncommitted: parseInt(uncommitted)||0, isAgent: manifest==='true', tpl, activity, color};
  });

  const a = projects.filter(p => p.isAgent);
  const hot = a.filter(p => p.activity === 'hot').length;
  const warm = a.filter(p => p.activity === 'warm').length;
  const cool = a.filter(p => p.activity === 'cool').length;
  const cold = a.filter(p => p.activity === 'cold').length;
  const totalDirty = projects.reduce((s,p) => s + p.uncommitted, 0);

  const rows = projects.map(p =>
    '<tr>' +
    '<td><span class="dot" style="color:' + p.color + '">\u25CF</span> <strong>' + p.name + '</strong></td>' +
    '<td><code>' + p.branch + '</code></td>' +
    '<td>' + p.last + '</td>' +
    '<td class="' + (p.uncommitted > 10 ? 'warn' : '') + '">' + p.uncommitted + '</td>' +
    '<td>' + (p.isAgent ? '<span class="badge">' + p.tpl + '</span>' : '<span class="dim">-</span>') + '</td>' +
    '<td style="color:' + p.color + '">' + p.activity + '</td>' +
    '<td>' + (p.isAgent ? '<button onclick="action(\'sync\',{project:\'' + scanDir + '/' + p.name + '\'})" title="Sync template">Sync</button>' : '') + '</td>' +
    '</tr>'
  ).join('');

  const css = '*{box-sizing:border-box}body{background:#0f0f1a;color:#e0e0e0;font-family:-apple-system,system-ui,sans-serif;margin:0;padding:30px 40px}h1{color:#fff;font-size:1.8em;margin:0 0 5px}.sub{color:#666;margin:0 0 25px;font-size:.9em}.bar{display:flex;justify-content:space-between;align-items:center;margin-bottom:25px}.acts{display:flex;gap:10px}.acts button{background:#1e3a5f;color:#e0e0e0;border:1px solid #2a4a6f;padding:8px 16px;border-radius:6px;cursor:pointer;font-size:.85em;transition:all .15s}.acts button:hover{background:#2a5a8f;border-color:#3a6a9f}.stats{display:grid;grid-template-columns:repeat(6,1fr);gap:15px;margin-bottom:25px}.stat{background:#161625;border:1px solid #252540;padding:15px;border-radius:10px;text-align:center}.stat-n{font-size:2em;font-weight:700;line-height:1.2}.stat-l{color:#666;font-size:.8em;margin-top:4px}table{width:100%;border-collapse:collapse;background:#161625;border-radius:10px;overflow:hidden}thead{background:#1a1a30}th{text-align:left;padding:12px 15px;color:#666;font-weight:600;font-size:.8em;text-transform:uppercase;letter-spacing:.5px}td{padding:10px 15px;border-bottom:1px solid #1f1f35;font-size:.9em}tr:hover{background:#1a1a2e}code{background:#1e1e35;padding:2px 6px;border-radius:3px;font-size:.85em;color:#8b8bab}.dot{font-size:1.2em;margin-right:4px}.badge{background:#1e3a2e;color:#4ade80;padding:2px 8px;border-radius:4px;font-size:.8em}.dim{color:#444}.warn{color:#f59e0b;font-weight:600}button{background:#1e2a3f;color:#a0b0c0;border:1px solid #2a3a4f;padding:4px 10px;border-radius:4px;cursor:pointer;font-size:.8em}button:hover{background:#2a3a5f}#toast{position:fixed;bottom:20px;right:20px;background:#1e3a5f;color:#fff;padding:12px 20px;border-radius:8px;display:none;font-size:.9em;box-shadow:0 4px 12px rgba(0,0,0,.4);z-index:100}#toast.err{background:#5f1e1e}#toast.show{display:block;animation:fi .3s}@keyframes fi{from{opacity:0;transform:translateY(10px)}to{opacity:1;transform:translateY(0)}}';

  const js = 'function toast(m,e){var t=document.getElementById("toast");t.textContent=m;t.className="show"+(e?" err":"");setTimeout(function(){t.className=""},4000)}async function action(n,p){toast("Running "+n+"...");try{var r=await fetch("/webhook/"+n,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({params:p||{}})});var d=await r.json();if(d.status==="complete")toast(n+": "+(d.message||d.total||d.agent_projects||"OK"));else toast(n+": "+(d.error||d.message||"error"),true)}catch(e){toast(n+" failed: "+e.message,true)}}';

  const html = '<!DOCTYPE html><html><head><meta charset="utf-8"><title>Agent Command Center</title>' +
    '<meta http-equiv="refresh" content="120">' +
    '<style>' + css + '</style></head><body>' +
    '<div class="bar"><div><h1>\u26A1 Agent Command Center</h1>' +
    '<p class="sub">' + new Date().toISOString().replace('T',' ').split('.')[0] + ' \u2022 ' + projects.length + ' repos \u2022 auto-refresh 2min</p></div>' +
    '<div class="acts">' +
    '<button onclick="action(\'health\')">\u2764 Health</button>' +
    '<button onclick="action(\'scan\')">\u{1F50D} Scan</button>' +
    '<button onclick="action(\'dep-check\')">\u{1F517} Deps</button>' +
    '<button onclick="action(\'weekly\')">\u{1F4CA} Weekly</button>' +
    '<button onclick="location.reload()">\u{1F504} Refresh</button>' +
    '</div></div>' +
    '<div class="stats">' +
    '<div class="stat"><div class="stat-n" style="color:#22c55e">' + hot + '</div><div class="stat-l">Hot (today)</div></div>' +
    '<div class="stat"><div class="stat-n" style="color:#eab308">' + warm + '</div><div class="stat-l">Warm (7d)</div></div>' +
    '<div class="stat"><div class="stat-n" style="color:#94a3b8">' + cool + '</div><div class="stat-l">Cool (30d)</div></div>' +
    '<div class="stat"><div class="stat-n" style="color:#ef4444">' + cold + '</div><div class="stat-l">Cold (30d+)</div></div>' +
    '<div class="stat"><div class="stat-n">' + a.length + '</div><div class="stat-l">Agent Projects</div></div>' +
    '<div class="stat"><div class="stat-n" style="color:' + (totalDirty > 50 ? '#ef4444' : '#eab308') + '">' + totalDirty + '</div><div class="stat-l">Uncommitted</div></div>' +
    '</div>' +
    '<table><thead><tr><th>Project</th><th>Branch</th><th>Last Commit</th><th>Dirty</th><th>Template</th><th>Status</th><th>Actions</th></tr></thead>' +
    '<tbody>' + rows + '</tbody></table>' +
    '<div id="toast"></div>' +
    '<script>' + js + '</script>' +
    '</body></html>';

  return [{json: {html}}];
} catch(e) {
  return [{json: {html: '<html><body style="background:#0f0f1a;color:red;padding:40px"><h1>Error</h1><pre>' + ((e.stderr||'') + e.message) + '</pre></body></html>'}}];
}
